DROP TABLE IF EXISTS `medications`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `medications` (
  `id` int NOT NULL AUTO_INCREMENT,
  `class` varchar(255) NOT NULL,
  `active_ingredient` varchar(255) DEFAULT NULL,
  `mechanism_of_action` text,
  `indication` text,
  `side_effects` text,
  `contraindication` text,
  `pregnancy_safe` tinyint(1) DEFAULT '0',
  `lactation_safe` tinyint(1) DEFAULT '0',
  `dosage` varchar(255) DEFAULT NULL,
  `dose_frequency` varchar(255) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `adult_dosage_1` text,
  `adult_frequency_1` text,
  `adult_dosage_2` text,
  `adult_frequency_2` text,
  `children_dosage_1` text,
  `children_frequency_1` text,
  `children_dosage_2` text,
  `children_frequency_2` text,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=238 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
